    std::uint64_t aOrbiterI = 0; std::uint64_t aOrbiterJ = 0; std::uint64_t aOrbiterK = 0;

    // [kdf-a arx]
    std::uint64_t aNonceWordA = TwistMix64::DiffuseC(pNonce * 0xDC81F9A02FE7966DULL + 0xA06D85F8BD4EEFAEULL);
    std::uint64_t aNonceWordB = TwistMix64::DiffuseA(pNonce * 0xE567E415D52EF70BULL + 0xB63EB78E1C8ED208ULL);
