    std::uint64_t aNonceWordF = TwistMix64::DiffuseA(pNonce * 0x923107B8D1025DB1ULL + 0x9AACA037E70AF333ULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseB(pNonce * 0xB95781673A199815ULL + 0xD4B299C665043231ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseB(pNonce * 0xAD4D41A917319111ULL + 0xF946FC0FD268723FULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseB(pNonce * 0xF720BEF55CF1FE8FULL + 0x9F247269D43C7CC8ULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0xA8CBDF0C8D6C7A13ULL + 0xFECA4C4A6DAD5A43ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseB(pNonce * 0x9C8DA053D8F5DEC7ULL + 0xC61B740BD82E0319ULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseA(pNonce * 0xFB8C970DB35B640DULL + 0xF8C36F672973309CULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseC(pNonce * 0xD50874532A288C9BULL + 0xB2D844D1BFEC5909ULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xAC5508C5411821BDULL + 0xED24DF69BB5389A1ULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseB(pNonce * 0x9883319D7B02CFB1ULL + 0xA1F4974918D9C85EULL);
    std::uint64_t aNonceWordP = TwistMix64::DiffuseA(pNonce * 0xB3606B7C419222E9ULL + 0xFB47F22F5864E0C8ULL);
    std::uint64_t aDomainWordIngress = pConstants->mIngress;
