            aScatter = (RotL64(aCarry, 5U) + RotL64(aPrevious, 21U)) + (RotL64(aIngress, 36U) ^ RotL64(aCross, 51U));
            aScatter = TwistMix64::DiffuseA(((aScatter ^ aDomainWordScatter) ^ aNonceWordF));
            //
            aOrbiterK = (((aWandererA + RotL64(aIngress, 51U)) + RotL64(aCarry, 19U)) + 15730602480199321733U) + aOrbiterAssignSaltD[((aIndex + 29U)) & S_SALT1];
            aOrbiterC = (aWandererC + RotL64(aScatter, 24U)) + 1389081616215012058U;
            aOrbiterJ = (((aWandererI + RotL64(aCross, 29U)) + 10139051131425088091U) + aOrbiterAssignSaltE[(((31U - aIndex) + 12U)) & S_SALT1]) + aNonceWordA;
            aOrbiterG = (aWandererK + RotL64(aPrevious, 43U)) + 15962362309178993181U;
