            aOrbiterG = ((aOrbiterG + aOrbiterJ) + 17080260069322726536U) + aOrbiterUpdateSaltA[((aIndex + 11U)) & S_SALT1];
            aOrbiterD = (aOrbiterD ^ aOrbiterG) ^ 3763786301803800199U;
            aOrbiterD = RotL64((aOrbiterD * 15508792279211633149U), 19U);
            //
            aOrbiterF = (aOrbiterF + aOrbiterD) + 1306416229944171691U;
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 17626458966450149658U;
            aOrbiterH = RotL64((aOrbiterH * 381193902485198465U), 43U);
            //
            aOrbiterC = ((aOrbiterC + aOrbiterA) + 678551757728664109U) + aOrbiterUpdateSaltF[((aIndex + 21U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterC) ^ 1089011703121554427U;
            aOrbiterE = RotL64((aOrbiterE * 3445439553751174491U), 39U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterH) + 16345021114555013737U) + aNonceWordN;
            aOrbiterA = (aOrbiterA ^ aOrbiterB) ^ 1063750026725578491U;
            aOrbiterA = RotL64((aOrbiterA * 8472701015420906637U), 11U);
            //
            aOrbiterE = ((aOrbiterE + aOrbiterF) + 14218623664526598886U) + aOrbiterUpdateSaltD[(((31U - aIndex) + 4U)) & S_SALT1];
            aOrbiterB = (aOrbiterB ^ aOrbiterE) ^ 8085256865813995755U;
            aOrbiterB = RotL64((aOrbiterB * 4652090807367049675U), 21U);
            //
            aOrbiterD = (aOrbiterD + aOrbiterI) + 3481926469321117449U;
            aOrbiterK = (aOrbiterK ^ aOrbiterD) ^ 15848892178877127753U;
            aOrbiterK = RotL64((aOrbiterK * 13949388835213467027U), 47U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterK) + 17553798851777887587U) + aNonceWordB;
            aOrbiterG = (aOrbiterG ^ aOrbiterH) ^ 3078887806434927417U;
            aOrbiterG = RotL64((aOrbiterG * 8010658003606024019U), 37U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterB) + 3083447908531392850U;
            aOrbiterC = (aOrbiterC ^ aOrbiterI) ^ 17588784931324279198U;
            aOrbiterC = RotL64((aOrbiterC * 9059647930510776731U), 13U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterG) + 17042566428606525168U) + aNonceWordO;
            aOrbiterF = ((aOrbiterF ^ aOrbiterA) ^ 2523078365826173871U) ^ aOrbiterUpdateSaltC[(((31U - aIndex) + 20U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 5170330007149889653U), 57U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterE) + 10552903711937360188U;
