            aIngress = aIngress + (aOrbiterI ^ RotL64(aOrbiterF, 13U));
            aIngress = aIngress + (RotL64(aOrbiterA, 43U) ^ aOrbiterE);
            aIngress = aIngress + RotL64(aOrbiterG, 11U);
            aIngress = TwistMix64::DiffuseA((aIngress + aScatter));
            //
            aWandererF = aWandererF ^ ((RotL64(aIngress, 21U) + RotL64(aOrbiterJ, 43U)) + aOrbiterA);
            aWandererG = aWandererG + (((RotL64(aScatter, 35U) + aOrbiterB) + RotL64(aOrbiterG, 10U)) + RotL64(aCarry, 3U));
            aWandererE = aWandererE ^ (((RotL64(aPrevious, 11U) + aOrbiterI) + RotL64(aOrbiterH, 47U)) + aNonceWordD);
            aWandererH = aWandererH + ((((RotL64(aCross, 38U) + aOrbiterJ) + RotL64(aOrbiterK, 13U)) + RotL64(aCarry, 29U)) + aWandererUpdateSaltE[((aIndex + 7U)) & S_SALT1]);
            aWandererD = aWandererD ^ ((RotL64(aPrevious, 47U) + aOrbiterD) + RotL64(aOrbiterK, 29U));
