            aOrbiterF = (aOrbiterF + aOrbiterG) + 7068359258812538069U;
            aOrbiterC = ((aOrbiterC ^ aOrbiterF) ^ 17979967886390531510U) ^ aOrbiterUpdateSaltE[((aIndex + 11U)) & S_SALT1];
            aOrbiterC = RotL64((aOrbiterC * 9101814136995971633U), 35U);
